import { useAppStore } from '../store/appStore';
import { motion } from 'framer-motion';

export default function LangToggle() {
  const { lang, setLang } = useAppStore();

  return (
    <motion.div
      className="fixed top-3 right-3 z-[60] flex bg-white/[0.03] backdrop-blur-xl p-0.5"
      style={{ border: '0.5px solid rgba(255, 255, 255, 0.06)' }}
      initial={{ opacity: 0, y: -10 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ delay: 0.5 }}
    >
      {(['tc', 'sc'] as const).map((l) => (
        <button
          key={l}
          className={`px-3 py-1.5 text-[10px] tracking-[2px] transition-all duration-300 ${
            lang === l
              ? 'bg-warm-gold/90 text-white'
              : 'text-warm-light/35 hover:text-warm-light/60'
          }`}
          onClick={() => setLang(l)}
        >
          {l === 'tc' ? '繁體' : '简体'}
        </button>
      ))}
    </motion.div>
  );
}
