import { useEffect, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { SLIDES } from '../data/slides';
import {
  fetchAnalyticsSummary,
  fetchSlideHeatmap,
  fetchFanScores,
  fetchTimeline,
} from '../api/reactionsApi';

interface Props {
  onClose: () => void;
}

// Format timestamp to readable date — handles ISO string or unix epoch
function formatDate(ts: string | number | null | undefined): string {
  if (ts == null) return '-';
  let d: Date;
  if (typeof ts === 'string') {
    // ISO 8601 string (YYYY-MM-DDTHH:mm:ss)
    d = new Date(ts.endsWith('Z') || ts.includes('+') ? ts : ts + 'Z');
  } else {
    // Unix epoch in seconds
    d = new Date(ts < 1e12 ? ts * 1000 : ts);
  }
  if (isNaN(d.getTime())) return '-';
  return d.toLocaleString('zh-HK', {
    month: 'short',
    day: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
  });
}

function formatDuration(sec: number): string {
  if (sec < 60) return `${sec}秒`;
  if (sec < 3600) return `${Math.floor(sec / 60)}分${sec % 60}秒`;
  return `${Math.floor(sec / 3600)}時${Math.floor((sec % 3600) / 60)}分`;
}

// Simple bar for visualizations
function Bar({ value, max, color = 'bg-james-orange' }: { value: number; max: number; color?: string }) {
  const pct = max > 0 ? (value / max) * 100 : 0;
  return (
    <div className="w-full h-3 bg-white/10 rounded-full overflow-hidden">
      <motion.div
        className={`h-full ${color} rounded-full`}
        initial={{ width: 0 }}
        animate={{ width: `${pct}%` }}
        transition={{ duration: 0.8, ease: 'easeOut' }}
      />
    </div>
  );
}

export default function AnalyticsDashboard({ onClose }: Props) {
  const [summary, setSummary] = useState<any>(null);
  const [heatmap, setHeatmap] = useState<any>(null);
  const [fanData, setFanData] = useState<any>(null);
  const [timeline, setTimeline] = useState<any>(null);
  const [activeTab, setActiveTab] = useState<'overview' | 'heatmap' | 'fans' | 'timeline'>('overview');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    Promise.all([
      fetchAnalyticsSummary(),
      fetchSlideHeatmap(),
      fetchFanScores(),
      fetchTimeline(30),
    ]).then(([s, h, f, t]) => {
      setSummary(s);
      setHeatmap(h);
      setFanData(f);
      setTimeline(t);
      setLoading(false);
    });
  }, []);

  const tabs = [
    { id: 'overview' as const, label: '📊 總覽' },
    { id: 'heatmap' as const, label: '🔥 作品熱力' },
    { id: 'fans' as const, label: '❤️ 粉絲指數' },
    { id: 'timeline' as const, label: '📈 趨勢' },
  ];

  return (
    <div className="fixed inset-0 bg-james-dark text-warm-light overflow-y-auto">
      {/* Header */}
      <div className="sticky top-0 z-50 bg-james-dark/95 backdrop-blur-sm border-b border-warm-gold/10">
        <div className="max-w-4xl mx-auto px-4 py-3 flex items-center justify-between">
          <div>
            <h1 className="text-lg text-warm-gold tracking-wider">🔬 阿占數據實驗室</h1>
            <p className="text-xs text-warm-light/40 mt-0.5">Data Science Dashboard</p>
          </div>
          <button
            onClick={onClose}
            className="text-warm-light/50 hover:text-warm-light text-sm px-3 py-1 border border-warm-light/20 rounded"
          >
            ✕ 關閉
          </button>
        </div>

        {/* Tab bar */}
        <div className="max-w-4xl mx-auto px-4 flex gap-1 pb-2 overflow-x-auto">
          {tabs.map((tab) => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={`px-4 py-2 text-xs tracking-wider rounded-t transition-all whitespace-nowrap ${
                activeTab === tab.id
                  ? 'bg-warm-gold/20 text-warm-gold border-b-2 border-warm-gold'
                  : 'text-warm-light/40 hover:text-warm-light/60'
              }`}
            >
              {tab.label}
            </button>
          ))}
        </div>
      </div>

      {/* Content */}
      <div className="max-w-4xl mx-auto px-4 py-6">
        {loading ? (
          <div className="flex flex-col items-center justify-center py-20">
            <motion.div
              animate={{ rotate: 360 }}
              transition={{ repeat: Infinity, duration: 1, ease: 'linear' }}
              className="text-4xl mb-4"
            >
              🔬
            </motion.div>
            <p className="text-warm-light/40 text-sm">正在分析數據...</p>
          </div>
        ) : (
          <AnimatePresence mode="wait">
            <motion.div
              key={activeTab}
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -10 }}
              transition={{ duration: 0.2 }}
            >
              {activeTab === 'overview' && <OverviewTab summary={summary} />}
              {activeTab === 'heatmap' && <HeatmapTab heatmap={heatmap} />}
              {activeTab === 'fans' && <FansTab fanData={fanData} />}
              {activeTab === 'timeline' && <TimelineTab timeline={timeline} />}
            </motion.div>
          </AnimatePresence>
        )}
      </div>
    </div>
  );
}

