import { useEffect, useState } from 'react';
import { useAppStore } from './store/appStore';
import Opening from './components/Opening';
import CardGallery from './components/CardGallery';
import EndingScreen from './components/EndingScreen';
import ShareModal from './components/ShareModal';
import QuizModal from './components/QuizModal';
import LangToggle from './components/LangToggle';
import AnalyticsDashboard from './components/AnalyticsDashboard';

function App() {
  const { phase, lang, initTracking } = useAppStore();
  const [showAnalytics, setShowAnalytics] = useState(false);

  // Initialize session tracking on mount
  useEffect(() => {
    initTracking();
  }, [initTracking]);

  // Secret key combo to open analytics: press 'a' 3 times quickly
  useEffect(() => {
    let pressCount = 0;
    let timer: ReturnType<typeof setTimeout>;

    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'a' || e.key === 'A') {
        pressCount++;
        clearTimeout(timer);
        timer = setTimeout(() => { pressCount = 0; }, 1000);
        if (pressCount >= 3) {
          pressCount = 0;
          setShowAnalytics(prev => !prev);
        }
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      clearTimeout(timer);
    };
  }, []);

  if (showAnalytics) {
    return <AnalyticsDashboard onClose={() => setShowAnalytics(false)} />;
  }

  return (
    <div className={`font-naikai ${lang === 'sc' ? 'lang-sc' : ''}`}>
      <LangToggle />

      {/* Opening animation */}
      {phase === 'opening' && <Opening />}

      {/* Main gallery */}
      {phase === 'gallery' && <CardGallery />}

      {/* Ending screen */}
      {phase === 'ending' && <EndingScreen />}

      {/* Modals */}
      <ShareModal />
      <QuizModal />
    </div>
  );
}

export default App;
