import { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { SLIDES, QUIZ_RESULTS, ACT_EMOJIS } from '../data/slides';
import { useAppStore } from '../store/appStore';

const QUIZ_QUESTIONS = {
  tc: [
    { q: '朋友失戀嚟搵你，你會？', a: ['笑佢蠢，然後帶佢食嘢', '陪佢喊一場', '分析佢點解會分手', '帶佢去旅行散心'] },
    { q: '人生最緊要係？', a: ['笑得出', '心安理得', '做自己', '留低痕跡'] },
    { q: '如果可以帶一樣嘢去荒島？', a: ['一本笑話書', '一樽好酒', '一副撲克牌', '一個人'] },
  ],
  sc: [
    { q: '朋友失恋来找你，你会？', a: ['笑他蠢，然后带他吃东西', '陪他哭一场', '分析他为啥分手', '带他去旅行散心'] },
    { q: '人生最重要的是？', a: ['笑得出', '心安理得', '做自己', '留下痕迹'] },
    { q: '如果可以带一样东西去荒岛？', a: ['一本笑话书', '一瓶好酒', '一副扑克牌', '一个人'] },
  ],
};

export default function QuizModal() {
  const { lang, showQuiz, setShowQuiz, quizResult, setQuizResult, trackQuiz } = useAppStore();
  const [step, setStep] = useState(0);
  const [answers, setAnswers] = useState<number[]>([]);
  const [showResult, setShowResult] = useState(false);

  const questions = QUIZ_QUESTIONS[lang];

  const handleAnswer = (ansIdx: number) => {
    const newAnswers = [...answers, ansIdx];
    setAnswers(newAnswers);

    if (step < questions.length - 1) {
      setStep(step + 1);
    } else {
      // Calculate result
      const counts = [0, 0, 0, 0];
      newAnswers.forEach((a) => counts[a]++);
      const maxIdx = counts.indexOf(Math.max(...counts));
      setQuizResult(maxIdx);
      trackQuiz('complete', maxIdx);
      setTimeout(() => setShowResult(true), 500);
    }
  };

  const handleReset = () => {
    setStep(0);
    setAnswers([]);
    setShowResult(false);
    setQuizResult(null);
  };

  const handleClose = () => {
    setShowQuiz(false);
    handleReset();
  };

  const handleShareResult = () => {
    if (quizResult === null) return;
    const result = QUIZ_RESULTS[lang][quizResult];
    const text = encodeURIComponent(
      `✨ 我的阿占態度是「${result.type}」${result.emoji}\n${result.desc}\n\n快來測測你是哪種態度！\nhttps://jamestyle.com`
    );
    if (navigator.share) {
      navigator.share({
        title: '阿占隨意 - 態度測試',
        text: `✨ 我的阿占態度是「${result.type}」${result.emoji}\n${result.desc}\n\nhttps://jamestyle.com`,
      }).catch(() => {});
    } else {
      window.open(`https://wa.me/?text=${text}`, '_blank');
    }
  };

  const result = quizResult !== null ? QUIZ_RESULTS[lang][quizResult] : null;
  const matchedSlides = quizResult !== null
    ? SLIDES.filter(s => s.act === quizResult).slice(0, 3)
    : [];

  return (
    <AnimatePresence>
      {showQuiz && (
        <motion.div
          className="fixed inset-0 z-[100] flex items-center justify-center"
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
        >
          <motion.div className="absolute inset-0 bg-black/70 backdrop-blur-md" onClick={handleClose} />

          <motion.div
            className="relative bg-[#161412] rounded-2xl p-7 w-full max-w-md mx-4 max-h-[85vh] overflow-y-auto"
            style={{ border: '0.5px solid rgba(196, 149, 106, 0.1)' }}
            initial={{ scale: 0.95, y: 20 }}
            animate={{ scale: 1, y: 0 }}
            exit={{ scale: 0.95, y: 20 }}
            transition={{ type: 'spring', damping: 28 }}
          >
            {/* Close */}
            <button className="absolute top-5 right-5 text-cream/25 text-sm tracking-wider hover:text-cream/50 transition-colors" onClick={handleClose}>✕</button>

            {!showResult ? (
              <>
                {/* Quiz header */}
                <div className="text-center mb-8">
                  <div className="text-3xl mb-4">✨</div>
                  <h3 className="text-lg text-cream/80 tracking-[4px] mb-2">
                    {lang === 'tc' ? '你是哪種阿占態度？' : '你是哪种阿占态度？'}
                  </h3>
                  <p className="text-[10px] text-warm-light/30 tracking-[2px]">
                    {lang === 'tc' ? '3 條問題，找到屬於你的人生哲學' : '3 道问题，找到属于你的人生哲学'}
                  </p>
                </div>

                {/* Progress dots */}
                <div className="flex justify-center gap-3 mb-7">
                  {questions.map((_, i) => (
                    <div key={i} className={`h-[0.5px] transition-all duration-500 ${i <= step ? 'bg-james-orange/50 w-8' : 'bg-white/[0.06] w-4'}`} />
                  ))}
                </div>

                {/* Question */}
                <AnimatePresence mode="wait">
                  <motion.div
                    key={step}
                    initial={{ x: 30, opacity: 0 }}
                    animate={{ x: 0, opacity: 1 }}
                    exit={{ x: -30, opacity: 0 }}
                  >
                    <p className="text-base text-cream/80 text-center mb-7 tracking-wide leading-relaxed">{questions[step].q}</p>
                    <div className="space-y-3.5">
                      {questions[step].a.map((ans, i) => (
                        <motion.button
                          key={i}
                          className="w-full p-4.5 text-left text-cream/60 text-base tracking-wide hermes-border rounded-xl transition-all duration-300 hover:bg-white/[0.03] hover:text-cream/80"
                          whileTap={{ scale: 0.98 }}
                          onClick={() => handleAnswer(i)}
                        >
                          <span className="mr-3 text-warm-gold/40 text-[10px] tracking-[2px]">{String.fromCharCode(65 + i)}.</span>
                          {ans}
                        </motion.button>
                      ))}
                    </div>
                  </motion.div>
                </AnimatePresence>
              </>
            ) : result ? (
              /* Result */
              <motion.div
                initial={{ opacity: 0, y: 15 }}
                animate={{ opacity: 1, y: 0 }}
                className="text-center"
              >
                <motion.div
                  className="text-5xl mb-5"
                  initial={{ scale: 0 }}
                  animate={{ scale: 1 }}
                  transition={{ type: 'spring', delay: 0.2 }}
                >
                  {result.emoji}
                </motion.div>

                <div className="hermes-divider mb-4" />

                <p className="text-[9px] text-warm-gold/40 tracking-[5px] mb-3 uppercase">
                  {lang === 'tc' ? '你的阿占態度是' : '你的阿占态度是'}
                </p>
                <h2 className="text-xl text-cream/80 mb-4 tracking-[4px]">{result.type}</h2>
                <p className="text-sm text-cream/40 leading-[2] mb-7 max-w-xs mx-auto tracking-wide">{result.desc}</p>

                {/* Matched slides */}
                <div className="flex justify-center gap-3 mb-7">
                  {matchedSlides.map(s => (
                    <motion.div
                      key={s.id}
                      className="w-18 h-18 rounded-lg overflow-hidden"
                      style={{ border: '0.5px solid rgba(196, 149, 106, 0.1)' }}
                      initial={{ y: 15, opacity: 0 }}
                      animate={{ y: 0, opacity: 1 }}
                      transition={{ delay: 0.4 }}
                    >
                      <img src={s.img} alt="" className="w-full h-full object-cover" />
                    </motion.div>
                  ))}
                </div>

                <div className="hermes-divider mb-5" />

                {/* Share result */}
                <motion.button
                  className="w-full py-4.5 bg-james-orange/90 text-white text-sm tracking-[3px] uppercase mb-3 rounded-xl shadow-lg shadow-james-orange/20 transition-all duration-300 hover:bg-james-orange"
                  whileTap={{ scale: 0.97 }}
                  onClick={handleShareResult}
                >
                  📤 {lang === 'tc' ? '分享你的態度' : '分享你的态度'}
                </motion.button>

                <motion.button
                  className="w-full py-4.5 text-sm text-cream/30 tracking-[3px] hermes-border uppercase rounded-xl transition-all duration-300 hover:text-cream/50"
                  whileTap={{ scale: 0.97 }}
                  onClick={handleReset}
                >
                  🔄 {lang === 'tc' ? '再測一次' : '再测一次'}
                </motion.button>
              </motion.div>
            ) : null}
          </motion.div>
        </motion.div>
      )}
    </AnimatePresence>
  );
}
